mapper.select:
SELECT log.id,
       log.user_id AS userId,
       log.name,
       log.accessType,
       log.create_time AS createTime,
       log.area_name AS areaName,
       log.room_id AS roomId,
       log.room_name AS roomName,
       log.project_group_names AS projectGroupNames
FROM aro_access_log log
WHERE 1 = 1

    AND (
        log.room_id IN

            #{rid}


            OR log.room_name IN

                #{rn}


    )


    AND log.room_name IN

        #{rn}




    AND log.area_name LIKE #{campusPattern}



    AND (
        log.name LIKE #{keywordPattern}
        OR log.user_id LIKE #{keywordPattern}
        OR log.project_group_names LIKE #{keywordPattern}
    )


    AND log.create_time >= #{startTime}


    AND log.create_time <= #{endTime}


    AND log.user_id NOT IN (SELECT user_id FROM twin_blacklist)

ORDER BY log.create_time ASC
